'use client'

import { useRouter } from 'next/navigation'
import GovNavbar from '@/components/government/navbar'
import EmergencyProblemCard from '@/components/government/emergency-problem-card'
import { Button } from '@/components/ui/button'
import { Empty } from '@/components/ui/empty'
import { Skeleton } from '@/components/ui/skeleton'
import { ArrowLeft } from 'lucide-react'
import { useState, useEffect } from 'react'

export default function EmergencyPage() {
  const router = useRouter()
  const [problems, setProblems] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    // TODO: Replace with actual API call to fetch emergency problems
    const fetchProblems = async () => {
      try {
        setIsLoading(true)
        // Simulate API delay
        await new Promise(resolve => setTimeout(resolve, 500))
        // TODO: Fetch from /api/emergency-problems or similar
        setProblems([])
      } catch (err) {
        setError('Failed to load emergency problems')
      } finally {
        setIsLoading(false)
      }
    }

    fetchProblems()
  }, [])

  const handleResponseSubmit = async (data: {
    complaintId: string
    responseText: string
    deadlineDate?: Date
  }) => {
    try {
      // TODO: Submit to /api/emergency-problems/:id/respond
      console.log('Response submitted:', data)
      // After successful submission, refetch the problems
    } catch (err) {
      console.error('Failed to submit response:', err)
    }
  }

  return (
    <div className="min-h-screen bg-background">
      <GovNavbar governmentName="Government Official" />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
        {/* Header with back button */}
        <div className="mb-8">
          <Button
            variant="ghost"
            onClick={() => router.back()}
            className="mb-4 text-muted-foreground hover:text-foreground gap-2"
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </Button>
          <h1 className="text-3xl font-bold text-foreground mb-2">Emergency Problems</h1>
          <p className="text-muted-foreground">
            Critical issues requiring immediate government action
          </p>
        </div>

        {/* Content */}
        {error ? (
          <Empty
            icon="alert-circle"
            title="Error loading problems"
            description="Failed to load emergency problems. Please try again."
          />
        ) : isLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {Array.from({ length: 4 }).map((_, i) => (
              <Skeleton key={i} className="h-96 bg-secondary rounded-lg" />
            ))}
          </div>
        ) : problems.length === 0 ? (
          <Empty
            icon="check-circle"
            title="No emergency problems"
            description="All critical issues have been resolved"
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {problems.map((problem) => (
              <EmergencyProblemCard
                key={problem.id}
                problem={problem}
                onResponseSubmit={handleResponseSubmit}
              />
            ))}
          </div>
        )}
      </main>
    </div>
  )
}
