'use client'

import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { MapPin, AlertTriangle, User } from 'lucide-react'
import { EmergencyProblem } from '@/lib/types'
import { useState } from 'react'
import ResponsePanel from './response-panel'

interface EmergencyProblemCardProps {
  problem: EmergencyProblem
  onResponseSubmit?: (data: {
    complaintId: string
    responseText: string
    deadlineDate?: Date
  }) => Promise<void>
  isLoading?: boolean
}

const PRIORITY_COLORS = {
  critical: 'bg-red-900/20 text-red-400 border-red-800/50',
  high: 'bg-orange-900/20 text-orange-400 border-orange-800/50',
  medium: 'bg-yellow-900/20 text-yellow-400 border-yellow-800/50',
}

const STATUS_COLORS = {
  new: 'bg-blue-900/20 text-blue-400',
  assigned: 'bg-purple-900/20 text-purple-400',
  'in-progress': 'bg-cyan-900/20 text-cyan-400',
  resolved: 'bg-green-900/20 text-green-400',
}

export default function EmergencyProblemCard({
  problem,
  onResponseSubmit,
  isLoading = false,
}: EmergencyProblemCardProps) {
  const [showResponse, setShowResponse] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)

  const handleResponseSubmit = async (data: {
    responseText: string
    deadlineDate?: Date
  }) => {
    setIsSubmitting(true)
    try {
      await onResponseSubmit?.({
        complaintId: problem.complaintId,
        ...data,
      })
      setShowResponse(false)
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <Card className="bg-card border-border overflow-hidden hover:border-accent/50 transition-colors">
      {/* Priority banner */}
      <div className={`px-4 py-2 border-b border-border ${PRIORITY_COLORS[problem.priority]}`}>
        <div className="flex items-center gap-2">
          <AlertTriangle className="w-4 h-4" />
          <span className="text-xs font-semibold uppercase">
            {problem.priority} Priority
          </span>
        </div>
      </div>

      <div className="p-4 space-y-3">
        {/* Title */}
        <h3 className="font-semibold text-foreground line-clamp-2">{problem.title}</h3>

        {/* Description */}
        <p className="text-sm text-muted-foreground line-clamp-2">{problem.description}</p>

        {/* Location */}
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <MapPin className="w-4 h-4 flex-shrink-0" />
          <span>{problem.location}</span>
        </div>

        {/* Citizen and Complaint Info */}
        <div className="flex flex-col gap-2 text-xs text-muted-foreground">
          <div className="flex items-center gap-2">
            <User className="w-4 h-4 flex-shrink-0" />
            <span>Citizen ID: {problem.citizenId}</span>
          </div>
          <div className="flex items-center gap-2">
            <span>Complaint ID: {problem.complaintId}</span>
          </div>
        </div>

        {/* Status badge */}
        <div className="flex items-center gap-2 pt-2">
          <Badge className={`text-xs ${STATUS_COLORS[problem.status]}`}>
            {problem.status.toUpperCase()}
          </Badge>
          <span className="text-xs text-muted-foreground">
            {new Date(problem.createdAt).toLocaleDateString()}
          </span>
        </div>

        {/* Response panel toggle */}
        {!showResponse ? (
          <button
            onClick={() => setShowResponse(true)}
            className="w-full mt-2 px-3 py-2 bg-accent hover:bg-accent/90 text-accent-foreground rounded text-sm font-medium transition-colors"
            disabled={isLoading}
          >
            Add Response
          </button>
        ) : (
          <button
            onClick={() => setShowResponse(false)}
            className="w-full mt-2 px-3 py-2 bg-secondary hover:bg-secondary/80 text-foreground rounded text-sm font-medium transition-colors"
          >
            Cancel
          </button>
        )}

        {showResponse && (
          <ResponsePanel
            complaintId={problem.complaintId}
            onSubmit={handleResponseSubmit}
            isLoading={isSubmitting}
          />
        )}
      </div>
    </Card>
  )
}
